// 创建一个自定义的 compute budget 指令
fn create_compute_budget_instruction(units: u64) -> Instruction {
    ComputeBudgetInstruction::set_compute_unit_limit(units).into()
}

// 在你的交易中使用这个指令
let compute_units = 500_000; // 设置自定义的计算单位
let compute_budget_instruction = create_compute_budget_instruction(compute_units);

// 将指令添加到你的交易中
