  chain: base,
  transport: http('https://mainnet.base.org'),
});

// 2. 创建钱包客户端（发送交易）
const account = privateKeyToAccount('0xYOUR_PRIVATE_KEY');
const walletClient = createWalletClient({
  account,
  chain: base,
  transport: http('https://mainnet.base.org'),
});
```

### 推荐工具一览

| 工具 | 用途 |
|------|------|
| **viem** | 底层链交互、类型安全的以太坊客户端 |
| **wagmi** | React Hooks，简化前端钱包连接 |
| **OnchainKit** | Coinbase 出品的 UI 组件库，快速构建 Base 应用 |

### ⚠️ 特别注意

使用 viem 时，Base 作为 L2 网络需要**特殊处理 Gas 费用**，必须同时考虑：
- **L2 执行费**
- **L1 数据费**

推荐使用 viem 内置的 L2 Gas 估算方法：

```typescript
import { estimateTotalFee } from 'viem/op-stack';

const totalFee = await estimateTotalFee(client, { account, to, data });
```

> 直接使用 `provider.getGasPrice()` 是常见错误，会导致 Gas 计算不准确！

Base 的 gas 费用与以太坊主网的主要区别在于它是一个 Layer 2 网络，因此其费用结构包含了两个部分：L2 执行费用和 L1 数据费用。仅仅计算 L2 gas 是不准确的，因为在 Base 上进行交易时，除了 L2 的执行费用外，还需要支付 L1 数据费用。

具体来说，L1 数据费用是通过预编译合约查询的，而 L2 执行费用则是基于交易的复杂性和所需的计算资源。因此，正确的计算方式应该是将 L2 执行费用和 L1 数据费用相加，以获得交易的总费用。

例如，以下是一个不正确的计算方式：

```typescript
const gasPrice = await provider.getGasPrice();
const gasCost = gasLimit * gasPrice; // 不准确！
```

而正确的计算方式应该是使用 viem 库中的 `estimateTotalFee` 方法来获取总费用：

```typescript
import { createPublicClient, http } from 'viem';
import { base } from 'viem/chains';

const client = createPublicClient({ chain: base, transport: http() });
const totalFee = await estimateTotalFee(client, { account, to, data });
```

这样可以确保你考虑到了所有相关的费用，从而避免在交易时出现意外的成本。

